void extract_parallel(fp* d_I, long d_Ne) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = exp(d_I[ei] / 255.0);
    }
}

void prepare_parallel(fp* d_I, fp* d_sums, fp* d_sums2, long d_Ne) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

void reduce_parallel(fp* d_sums, fp* d_sums2, long d_Ne, long d_no, int d_mul, int gridDim) {
    int nf = NUMBER_THREADS - (gridDim * NUMBER_THREADS - d_no);
    int df = 0;

    #pragma omp parallel
    {
        int bx = omp_get_thread_num();
        int tx = bx % NUMBER_THREADS;
        int ei = bx * NUMBER_THREADS + tx;

        static fp d_psum[NUMBER_THREADS];
        static fp d_psum2[NUMBER_THREADS];

        if (d_no > ei) {
            d_psum[tx] = d_sums[ei * d_mul];
            d_psum2[tx] = d_sums2[ei * d_mul];
        }

        #pragma omp barrier

        if (nf == NUMBER_THREADS) {
            for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (0 == (tx + 1) % i) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                #pragma omp barrier
            }

            if (tx == (NUMBER_THREADS - 1)) {
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        } else {
            if (bx != (gridDim - 1)) {
                for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                    if (0 == (tx + 1) % i) {
                        d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                        d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                    }
                    #pragma omp barrier
                }

                if (tx == (NUMBER_THREADS - 1)) {
                    d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                    d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
                }
            } else {
                for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                    if (nf >= i) {
                        df = i;
                    }
                }

                for (int i = 2; df >= i; i = 2 * i) {
                    if ((tx + 1) % i == 0 && df > tx) {
                        d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                        d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                    }
                    #pragma omp barrier
                }

                if ((df - 1) == tx) {
                    for (int i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                        d_psum[tx] = d_psum[tx] + d_sums[i];
                        d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                    }

                    d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                    d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
                }
            }
        }
    }
}

void srad_parallel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne, int* d_iN, int* d_iS, int* d_jE, int* d_jW, fp* d_dN, fp* d_dS, fp* d_dW, fp* d_dE, fp d_q0sqr, fp* d_c, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        int row;
        int col;

        fp d_Jc;
        fp d_dN_loc, d_dS_loc, d_dW_loc, d_dE_loc;
        fp d_c_loc;
        fp d_G2, d_L, d_num, d_den, d_qsqr;

        row = (ei + 1) % d_Nr - 1;
        col = (ei + 1) / d_Nr + 1 - 1;
        if (0 == (ei + 1) % d_Nr) {
            row = d_Nr - 1;
            col -= 1;
        }

        if (d_Ne > ei) {
            d_Jc = d_I[ei];

            d_dN_loc = d_I[d_iN[row] + d_Nr * col] - d_Jc;
            d_dS_loc = d_I[d_iS[row] + d_Nr * col] - d_Jc;
            d_dW_loc = d_I[row + d_Nr * d_jW[col]] - d_Jc;
            d_dE_loc = d_I[row + d_Nr * d_jE[col]] - d_Jc;

            d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);

            d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

            d_num = (0.5 * d_G2) - ((1.0 / 16.0) * (d_L * d_L));
            d_den = 1 + (0.25 * d_L);
            d_qsqr = d_num / (d_den * d_den);

            d_den = (d_qsqr - d_q0sqr) / (d_q0sqr * (1 + d_q0sqr));
            d_c_loc = 1.0 / (1.0 + d_den);

            if (d_c_loc < 0) {
                d_c_loc = 0;
            } else if (d_c_loc > 1) {
                d_c_loc = 1;
            }

            d_dN[ei] = d_dN_loc;
            d_dS[ei] = d_dS_loc;
            d_dW[ei] = d_dW_loc;
            d_dE[ei] = d_dE_loc;
            d_c[ei] = d_c_loc;
        }
    }
}

void srad2_parallel(fp d_lambda, int d_Nr, int d_Nc, long d_Ne, int* d_iN, int* d_iS, int* d_jE, int* d_jW, fp* d_dN, fp* d_dS, fp* d_dW, fp* d_dE, fp* d_c, fp* d_I) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        int row;
        int col;

        fp d_cN, d_cS, d_cW, d_cE;
        fp d_D;

        row = (ei + 1) % d_Nr - 1;
        col = (ei + 1) / d_Nr + 1 - 1;
        if ((ei + 1) % d_Nr == 0) {
            row = d_Nr - 1;
            col = col - 1;
        }

        if (ei < d_Ne) {
            d_cN = d_c[ei];
            d_cS = d_c[d_iS[row] + d_Nr * col];
            d_cW = d_c[ei];
            d_cE = d_c[row + d_Nr * d_jE[col]];

            d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];

            d_I[ei] = d_I[ei] + 0.25 * d_lambda * d_D;
        }
    }
}

void compress_parallel(fp* d_I, long d_Ne) {
    #pragma omp parallel for
    for (long ei = 0; ei < d_Ne; ei++) {
        d_I[ei] = log(d_I[ei]) * 255;
    }
}

void kernel_gpu_opencl_wrapper(fp* image, int Nr, int Nc, long Ne, int niter, fp lambda, long NeROI, int* iN, int* iS, int* jE, int* jW, int iter, int mem_size_i, int mem_size_j) {

#ifdef TIMING
    struct timeval tv;
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_h2d_start, tv_h2d_end;
    struct timeval tv_d2h_start, tv_d2h_end;
    struct timeval tv_kernel_start, tv_kernel_end;
    struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0, d2h_time = 0, close_time = 0, total_time = 0;

    gettimeofday(&tv_total_start, NULL);
#endif

    printf("Platform: OpenMP\n");
    printf("Device: CPU\n");

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    int blocks_x;

    int mem_size;
    mem_size = sizeof(fp) * Ne;

    fp* d_I = (fp*)malloc(mem_size);
    fp* d_iN = (fp*)malloc(mem_size_i);
    fp* d_iS = (fp*)malloc(mem_size_i);
    fp* d_jE = (fp*)malloc(mem_size_j);
    fp* d_jW = (fp*)malloc(mem_size_j);
    fp* d_dN = (fp*)malloc(mem_size);
    fp* d_dS = (fp*)malloc(mem_size);
    fp* d_dW = (fp*)malloc(mem_size);
    fp* d_dE = (fp*)malloc(mem_size);
    fp* d_c = (fp*)malloc(mem_size);
    fp* d_sums = (fp*)malloc(mem_size);
    fp* d_sums2 = (fp*)malloc(mem_size);

    memcpy(d_I, image, mem_size);
    memcpy(d_iN, iN, mem_size_i);
    memcpy(d_iS, iS, mem_size_i);
    memcpy(d_jE, jE, mem_size_j);
    memcpy(d_jW, jW, mem_size_j);

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
#endif

    int blocks_work_size;
    size_t global_work_size;
    blocks_x = Ne / NUMBER_THREADS;
    if (Ne % NUMBER_THREADS != 0) {
        blocks_x = blocks_x + 1;
    }
    blocks_work_size = blocks_x;
    global_work_size = blocks_work_size * NUMBER_THREADS;

    printf("max # of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n", (int)(global_work_size / NUMBER_THREADS), NUMBER_THREADS);

    fp total;
    fp total2;
    fp meanROI;
    fp meanROI2;
    fp varROI;
    fp q0sqr;

    int blocks2_x;
    int blocks2_work_size;
    size_t global_work_size2;
    long no;
    int mul;
    int mem_size_single = sizeof(fp) * 1;

    extract_parallel(d_I, Ne);

    prepare_parallel(d_I, d_sums, d_sums2, Ne);

    printf("Iterations Progress: hidden");

    for (iter = 0; iter < niter; iter++) {

        fflush(NULL);

        prepare_parallel(d_I, d_sums, d_sums2, Ne);

        blocks2_work_size = blocks_work_size;
        global_work_size2 = global_work_size;
        no = Ne;
        mul = 1;

        while (blocks2_work_size != 0) {

            reduce_parallel(d_sums, d_sums2, Ne, no, mul, blocks2_work_size);

            no = blocks2_work_size;
            if (blocks2_work_size == 1) {
                blocks2_work_size = 0;
            } else {
                mul = mul * NUMBER_THREADS;
                blocks_x = blocks2_work_size / NUMBER_THREADS;
                if (blocks2_work_size % NUMBER_THREADS != 0) {
                    blocks_x = blocks_x + 1;
                }
                blocks2_work_size = blocks_x;
                global_work_size2 = blocks2_work_size * NUMBER_THREADS;
            }
        }

        total = d_sums[0];
        total2 = d_sums2[0];

        meanROI = total / (fp)(NeROI);
        meanROI2 = meanROI * meanROI;
        varROI = (total2 / (fp)(NeROI)) - meanROI2;
        q0sqr = varROI / meanROI2;

        srad_parallel(lambda, Nr, Nc, Ne, (int*)d_iN, (int*)d_iS, (int*)d_jE, (int*)d_jW, d_dN, d_dS, d_dW, d_dE, q0sqr, d_c, d_I);

        srad2_parallel(lambda, Nr, Nc, Ne, (int*)d_iN, (int*)d_iS, (int*)d_jE, (int*)d_jW, d_dN, d_dS, d_dW, d_dE, d_c, d_I);
    }

    printf("\n");

    compress_parallel(d_I, Ne);

    memcpy(image, d_I, mem_size);

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    free(d_I);
    free(d_c);
    free(d_iN);
    free(d_iS);
    free(d_jE);
    free(d_jW);
    free(d_dN);
    free(d_dS);
    free(d_dE);
    free(d_dW);
    free(d_sums);
    free(d_sums2);

#ifdef TIMING
    printf("Time spent in different stages of the application:\n");
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0 + (float)tv.tv_usec / 1000.0;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}
